#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2005;
LL n,Bl,sz[N],dp[N][N];
vector<pLL> g[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS(int u,int fa){
    sz[u]=1;dp[u][0]=0,dp[u][1]=0;
    for(auto [v,w]:g[u])if(v^fa){
        DFS(v,u);sz[u]+=sz[v];
        for(LL i=min(Bl,sz[u]);i>=0;i--){
            if(dp[u][i]!=-1)dp[u][i]+=dp[v][0]+sz[v]*(n-Bl-sz[v])*w;
            for(LL j=min(i,sz[v]);j>=1;j--){
                if(dp[u][i-j]==-1||dp[v][j]==-1)continue;
                LL cnt=j*(Bl-j)+(sz[v]-j)*(n-Bl-sz[v]+j);
                dp[u][i]=max(dp[u][i],dp[u][i-j]+dp[v][j]+cnt*w);
            }
        }
    }
}
int main(){
    n=read(),Bl=read();
    if(n-Bl<Bl)Bl=n-Bl;
    for(int i=1;i<n;i++){
        LL x=read(),y=read(),z=read();
        g[x].pb({y,z}),g[y].pb({x,z});
    }memset(dp,-1,sizeof(dp));
    DFS(1,0);cout<<dp[1][Bl]<<"\n";
    return 0;
}
